import{_ as s,c as a,o as e,a1 as t}from"./chunks/framework.C46D9NsM.js";const k=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/faq.md","filePath":"zh-CN/guide/faq.md","lastUpdated":1718964110000}'),i={name:"zh-CN/guide/faq.md"},l=t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><details class="details custom-block"><summary>调用接口报 404</summary><p>目前没有支持全部的 OneBot 规范接口，请检查是否调用了不支持的接口。</p></details><details class="details custom-block"><summary>如何使用 CQ 码？</summary><p>将消息上报类型格式从消息段更改为 CQ 码即可。</p></details><details class="details custom-block"><summary>二维码无法扫描</summary><p>NapCat 会自动保存二维码到目录，可以手动打开图片扫描。</p><p>如果无法访问本地目录（例如，纯命令行页面），可以将二维码解析的 URL 复制到二维码生成网站上重新生成二维码，然后再用手机 QQ 扫描。</p><p>注意动作要快，因为二维码是会过期的！</p></details><details class="details custom-block"><summary>语音、视频发送失败</summary><p>这种情况需要你手动配置 ffmpeg 路径。ffmpeg 可以点击<a href="/zh-CN/guide/ffmpeg">这里</a>下载。</p><p>将 ffmpeg 目录加入环境变量，如果仍未生效，可以修改 NapCat 启动脚本加入 FFMPEG_PATH 变量，指定到 ffmpeg 程序的完整路径。例如，Windows 上，可以修改 napcat.ps1，在第一行前加入</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FFMPEG_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;d:\\ffmpeg\\bin\\ffmpeg.exe&quot;</span></span></code></pre></div></details><details class="details custom-block"><summary>Windows 系统启动，出现 QQ 本体界面</summary><p>尝试管理员启动 NapCat。如果仍然失败，请反馈 NapCat 开发群。</p></details><details class="details custom-block"><summary>出现 <code>error code v2:-1</code> 之类的提示</summary><p>QQ 本身问题，正常现象，不影响使用。</p></details><details class="details custom-block"><summary>登录提示出现“网络环境不稳定”“不在同一网络”</summary><p>如果在服务器扫码登录提示出现网络环境不稳定/不在同一网络，可以尝试在本地登录后，将 QQ 本身的配置传到服务器相同目录覆盖。</p><p>Linux 下 QQ 配置的目录位于 <code>~/.config/QQ</code>；Windows 下一般是<strong>文档下的 QQ 文件夹</strong>（默认情况是 <code>&lt;系统盘&gt;:\\Users (用户)\\Documents\\Tencent Files</code>），具体可以打开 QQ 设置，进入“存储管理”一栏查看。</p><p>或者，手机使用 VPN 等方式连接到服务器网络，使手机和服务器在同一网络，也可解决此问题。</p></details><details class="details custom-block"><summary>Windows 运行出现 “sqlite3 不是 win32 程序”</summary><p>运行时，若出现 <code>node_sqlite3.node is not a valid Win32 application</code>，请检查下载的是否是 Windows 版本的 NapCatQQ，检查是否是安装的 64 位版本的 QQ。</p></details><details class="details custom-block"><summary>“ MH Hook Hk sub XXXX Error ” 崩溃报错</summary><p>如果你的此前使用LLOneBot，且使用过Liteloader某某一键包、或者使用了验证跳过的dll。</p><p>出现此错误，应该删除一键包和相关dll或完全清除重装QQNT。</p></details>',10),o=[l];function d(p,c,m,n,r,u){return e(),a("div",null,o)}const _=s(i,[["render",d]]);export{k as __pageData,_ as default};
